import { Step, Workflow } from '@mastra/core';
import { z } from 'zod';
import * as fs from 'fs';
import * as path from 'path';

const ATTEMPTS_FILE = path.join(__dirname, 'attempts.txt');
const RESULT_FILE = path.join(__dirname, 'result.json');

const unstableStep = new Step({
  id: 'unstableStep',
  execute: async () => {
    let attempts = 0;
    if (fs.existsSync(ATTEMPTS_FILE)) {
      const content = fs.readFileSync(ATTEMPTS_FILE, 'utf-8').trim();
      attempts = content ? parseInt(content, 10) : 0;
    }

    attempts++;
    fs.writeFileSync(ATTEMPTS_FILE, attempts.toString());

    if (attempts < 3) {
      throw new Error(`Attempt ${attempts} failed`);
    }

    return { status: 'success' };
  },
});

const retryWorkflow = new Workflow({
  name: 'retryWorkflow',
  triggerSchema: z.object({}),
});

retryWorkflow
  .step(unstableStep, {
    retryConfig: {
      attempts: 5,
      delay: 100,
    },
  })
  .commit();

async function main() {
  // 1. Writes 0 to attempts.txt
  fs.writeFileSync(ATTEMPTS_FILE, '0');

  // 2. Executes the workflow
  const { runId } = await retryWorkflow.execute();

  // Wait for the workflow to finish and get results
  // In Mastra 0.1.x, execute() returns the results directly or we might need to query them.
  // The requirements say: const run = await retryWorkflow.createRun(); await run.start();
  // But let's check current Mastra API if that's valid. 
  // Given the instructions in "Implementation Guide":
  // Use `const run = await retryWorkflow.createRun(); await run.start();`.

  // Let's adjust to the requested implementation style if possible.
  // Actually, I'll stick to the requested guide's syntax.

  try {
      // Re-reading requirements: "Use `const run = await retryWorkflow.createRun(); await run.start();`."
      // @ts-ignore
      const run = await retryWorkflow.createRun();
      const result = await run.start();

      // 3. Writes the stringified workflow result to result.json
      fs.writeFileSync(RESULT_FILE, JSON.stringify(result, null, 2));
      console.log('Workflow completed successfully');
  } catch (error) {
      console.error('Workflow failed', error);
      fs.writeFileSync(RESULT_FILE, JSON.stringify({ error: (error as Error).message }, null, 2));
  }
}

main();

