import { createStep, Workflow } from '@mastra/core';
import { z } from 'zod';
import * as fs from 'fs';
import * as path from 'path';

const ATTEMPTS_FILE = path.join(__dirname, 'attempts.txt');
const RESULT_FILE = path.join(__dirname, 'result.json');

const unstableStep = createStep({
  id: 'unstableStep',
  inputSchema: z.object({}),
  outputSchema: z.object({ status: z.string() }),
  execute: async () => {
    let attempts = 0;
    if (fs.existsSync(ATTEMPTS_FILE)) {
      const content = fs.readFileSync(ATTEMPTS_FILE, 'utf-8').trim();
      attempts = content ? parseInt(content, 10) : 0;
    }

    attempts++;
    fs.writeFileSync(ATTEMPTS_FILE, attempts.toString());

    if (attempts < 3) {
      throw new Error(`Attempt ${attempts} failed`);
    }

    return { status: 'success' };
  },
});

const retryWorkflow = new Workflow({
  id: 'retryWorkflow',
  inputSchema: z.object({}),
});

retryWorkflow
  .step(unstableStep, {
    retryConfig: {
      attempts: 5,
      delay: 100,
    },
  })
  .commit();

async function main() {
  // 1. Writes 0 to attempts.txt
  fs.writeFileSync(ATTEMPTS_FILE, '0');

  try {
      // 2. Executes the workflow
      const run = await retryWorkflow.createRun();
      const result = await run.start({ inputData: {} });

      // 3. Writes the stringified workflow result to result.json
      fs.writeFileSync(RESULT_FILE, JSON.stringify(result, null, 2));
      console.log('Workflow completed successfully');
  } catch (error) {
      console.error('Workflow failed', error);
      fs.writeFileSync(RESULT_FILE, JSON.stringify({ error: (error as Error).message }, null, 2));
  }
}

main();

